R programming language 3.3.3 of later Comprehensive R Archive Network The R Foundation # Завантаження необхідних пакетів # Loading necessary packages library(terra) # робота з растровими даними | for working with raster data library(sf) # робота з векторними даними | for working with vector data # 1. Завантаження полігону (shapefile) # 1.Loading the polygon (shapefile) poly &lt;-st_read(&#34;D:/Science/Хортиця/Form_3.shp&#34;) poly_vect&lt;- vect(poly) # 2. Задаємо шлях до SAFE-продукту Sentinel-2 # 2. Definethe path to the Sentinel-2 SAFE product safe_folder&lt;- &#34;D:/GISData/SENTINEL/S2B_MSIL2A_20220824T083559_N0400_R064_T36UXU_20220824T100829.SAFE&#34; # 3. Отримання списку всіх файлів з розширенням .jp2(рекурсивно) # 3.Retrieve a list of all files with the .jp2 extension (recursively) all_files&lt;- list.files(safe_folder, pattern = &#34;\.jp2$&#34;, recursive = TRUE,full.names = TRUE) cat(&#34;Знайдено JP2 файлів (без фільтрації):&#34;,length(all_files), &#34;
&#34;) #Print count of found JP2 files without filtering # Відфільтруємо файли, що містять &#34;IMG_DATA&#34; вшляху (як правило, саме там знаходяться потрібні канали) # Filterthe files that contain &#34;IMG_DATA&#34; in their path (usually where therequired bands are located) file_paths&lt;- all_files[grepl(&#34;IMG_DATA&#34;, all_files)] cat(&#34;Знайдено файлів уIMG_DATA:&#34;, length(file_paths), &#34;
&#34;) print(file_paths) if(length(file_paths)== 0) { stop(&#34;Не знайдено файлів .jp2 у підкаталозі IMG_DATA. Перевірте шлях таpattern.&#34;) # Stop execution if no .jp2 files are foundin IMG_DATA folder } # 4. Встановлюємо рік зйомки (для іменування файлів) # 4. Setthe image acquisition year (for file naming) year_of_image&lt;- &#34;2022&#34; # 5. Встановлюємо вихідну папку та створюємо її, якщо неіснує # 5.Specify the output folder and create it if it does not exist output_folder&lt;- &#34;D:/GIS Data/SENTINEL/Output&#34; if(!dir.exists(output_folder)) { dir.create(output_folder, recursive = TRUE) } # 6. Цикл обробки файлів # 6. Loopfor processing files for(file_pathin file_paths) { cat(&#34;Обробляється файл:&#34;, file_path, &#34;
&#34;) # Processing the file # Завантаження зображення # Load the image r_band &lt;- try(rast(file_path), silent =TRUE) if(inherits(r_band, &#34;try-error&#34;)){ cat(&#34;Не вдалося завантажитифайл:&#34;, file_path, &#34;
&#34;) next } # Обрізаннязображення за межами полігону # Crop the image to the polygon boundaries r_crop &lt;- try(crop(r_band, poly_vect),silent = TRUE) if(inherits(r_crop, &#34;try-error&#34;)){ cat(&#34;Помилка crop для:&#34;, file_path, &#34;
&#34;) next } r_mask &lt;- try(mask(r_crop, poly_vect),silent = TRUE) if(inherits(r_mask, &#34;try-error&#34;)){ cat(&#34;Помилка mask для:&#34;, file_path, &#34;
&#34;) next } # Перевірка роздільної здатності # Check the current resolution current_res &lt;- res(r_mask) cat(&#34;Поточна роздільна здатність:&#34;,current_res[1], &#34;x&#34;, current_res[2], &#34;
&#34;) # Ресемплінг до 10 метрів, якщо потрібно # Resample to 10 meters resolution if needed if(any(current_res != 10)) { ext_r &lt;- ext(r_mask) ncol_new &lt;- ceiling((ext_r[2] -ext_r[1]) / 10) nrow_new &lt;- ceiling((ext_r[4] -ext_r[3]) / 10) target &lt;- rast(ext = ext_r, ncols =ncol_new, nrows = nrow_new, crs = crs(r_mask)) r_final &lt;- try(resample(r_mask, target,method = &#34;bilinear&#34;), silent = TRUE) if(inherits(r_final,&#34;try-error&#34;)){ cat(&#34;Помилка resample для:&#34;, file_path, &#34;
&#34;) next } } else { r_final &lt;- r_mask } # Формування імені файлу: використання базового імені + рік # Form the file name using the base name andthe year base_name &lt;-tools::file_path_sans_ext(basename(file_path)) output_path &lt;- file.path(output_folder,paste0(base_name, &#34;_&#34;, year_of_image, &#34;.tif&#34;)) # Запис результату # Write the result raster to file tryCatch({ writeRaster(r_final, output_path, overwrite= TRUE) cat(&#34;Збережено:&#34;, output_path, &#34;

&#34;) }, error = function(e){ cat(&#34;Помилка запису для:&#34;,file_path, &#34;
&#34;, e, &#34;
&#34;) }) } cat(&#34;Обробку завершено!
&#34;) # Processing complete! # Розрахунок індексів #Calculation of indices library(terra) # Ensure terra is loaded (if not already) year =&#34;2024&#34; # === 1. ШЛЯХИ === # === 1.PATHS === input_folder&lt;- &#34;D:/GIS Data/SENTINEL/Output&#34; output_folder&lt;- paste0(&#34;D:/GIS Data/SENTINEL/Indices_&#34;, year) dir.create(output_folder,showWarnings = FALSE, recursive = TRUE) # === 2. КАНАЛИ === # === 2.BANDS === bands_codes&lt;- c( B1 =&#34;B01&#34;, B2 =&#34;B02&#34;, B3 =&#34;B03&#34;, B4 =&#34;B04&#34;, B5 =&#34;B05&#34;, B6 =&#34;B06&#34;, B7 =&#34;B07&#34;, B8 =&#34;B08&#34;, B8A = &#34;B8A&#34;, B9 = &#34;B09&#34;, B11 =&#34;B11&#34;, B12 =&#34;B12&#34; ) # === 3. ПОШУК ФАЙЛУ ЗА КАНАЛОМ === # === 3.SEARCH FOR FILE BY BAND === get_input_band&lt;- function(band_code, year = year) { files &lt;- list.files(input_folder, pattern= paste0(band_code, &#34;.*&#34;, year, &#34;\.tif$&#34;), full.names =TRUE) if (length(files) == 0) { warning(paste(&#34;Не знайдено файл для&#34;, band_code, &#34;за&#34;, year)) return(NA) } return(files[1]) } # === 4. ЗАВАНТАЖЕННЯ КАНАЛІВ === # === 4.LOADING BANDS === bands &lt;-list() for (b innames(bands_codes)) { cat(&#34;Завантаження&#34;, b, &#34;
&#34;) # Loading band path &lt;- get_input_band(bands_codes[b],year = year) if (!is.na(path)) { bands[[b]] &lt;- rast(path) cat(&#34; ‱&#34;, basename(path),&#34;
&#34;) } else { cat(&#34; ‱ Пропущено
&#34;) } } # === 5. БАЗОВЕ ІМ&#39;Я === # === 5.SET BASE NAME === b2_file&lt;- get_input_band(&#34;B02&#34;, year = year) if(is.na(b2_file)) stop(&#34;Не знайдено B02 для іменування індексів&#34;) base_name&lt;- tools::file_path_sans_ext(basename(b2_file)) year_of_image&lt;- year # === 5.1 ПРИВЕДЕННЯ ДОШАБЛОНУ B2 === # === 5.1ALIGN TO B2 TEMPLATE === if(!&#34;B2&#34; %in% names(bands)) stop(&#34;Канал B2 відсутній — шаблон неможливий&#34;) template&lt;- bands$B2 for (b innames(bands)) { if (b == &#34;B2&#34;) next if (!inherits(bands[[b]],&#34;SpatRaster&#34;)) next r &lt;- bands[[b]] if (!compareGeom(r, template, stopOnError =FALSE)) { cat(&#34;🔧Приведення до шаблону:&#34;, b, &#34;
&#34;) bands[[b]] &lt;- resample(r, template, method =&#34;bilinear&#34;) } } # === ЗБЕРЕЖЕННЯ ІНДЕКСІВ (тільки абревіатура + рік) === # ===SAVING INDICES (using abbreviation + year) === save_index&lt;- function(r, abbr) { out_name &lt;- paste0(abbr, &#34;_&#34;,year_of_image, &#34;.tif&#34;) out_path &lt;- file.path(output_folder,out_name) writeRaster(r, out_path, overwrite = TRUE) cat(&#34;💾 Збережено:&#34;, out_name, &#34;
&#34;) } # === 7. РОЗРАХУНОК ІНДЕКСУ З ПЕРЕВІРКОЮ === # === 7.CALCULATE INDEX WITH CHECK === try_index&lt;- function(expr, required_bands, abbr) { if (all(required_bands %in% names(bands))&amp;&amp; all(sapply(bands[required_bands],function(x) inherits(x, &#34;SpatRaster&#34;)))) { result &lt;- tryCatch(eval(expr), error =function(e) NA) if (inherits(result,&#34;SpatRaster&#34;)) { save_index(result, abbr) } else { cat(&#34;‱ Індекс&#34;, abbr, &#34;не обчислено (результат не SpatRaster)
&#34;) } } else { cat(&#34;‱ Індекс&#34;,abbr, &#34;пропущено (немає каналів:&#34;, paste(setdiff(required_bands,names(bands)), collapse = &#34;, &#34;), &#34;)
&#34;) } } # === 8. РОЗРАХУНОК ІНДЕКСІВ === # === 8.CALCULATE INDICES === try_index(quote((bands$B1- bands$B2)/(bands$B1 + bands$B2)), c(&#34;B1&#34;, &#34;B2&#34;),&#34;AC_Index&#34;) try_index(quote((bands$B4- bands$B2)/(bands$B2 + bands$B4)), c(&#34;B2&#34;, &#34;B4&#34;),&#34;NDIO&#34;) try_index(quote((bands$B3- bands$B12)/(bands$B3 + bands$B12)), c(&#34;B3&#34;, &#34;B12&#34;),&#34;RI&#34;) try_index(quote((bands$B8A- bands$B3)/(bands$B8A + bands$B3)), c(&#34;B3&#34;, &#34;B8A&#34;),&#34;NDGCI&#34;) try_index(quote((bands$B3- bands$B2)/(bands$B2 + bands$B3)), c(&#34;B2&#34;, &#34;B3&#34;),&#34;BIG2&#34;) try_index(quote((bands$B8- bands$B2)/(bands$B8 + bands$B4)), c(&#34;B2&#34;, &#34;B8&#34;),&#34;SIPI&#34;) try_index(quote((bands$B4- bands$B2)/(bands$B5 + bands$B11)), c(&#34;B4&#34;, &#34;B2&#34;,&#34;B5&#34;, &#34;B11&#34;), &#34;SVSI&#34;) try_index(quote((bands$B8- bands$B5)/(bands$B8 + bands$B5)), c(&#34;B8&#34;, &#34;B5&#34;),&#34;NDREI&#34;) try_index(quote((bands$B7- bands$B5)/(bands$B7 + bands$B5)), c(&#34;B7&#34;, &#34;B6&#34;),&#34;NDRE&#34;) try_index(quote((bands$B6- bands$B11)/(bands$B6 + bands$B11)), c(&#34;B6&#34;, &#34;B11&#34;),&#34;NDBaI&#34;) try_index(quote((bands$B11- bands$B12)/(bands$B11 + bands$B12)), c(&#34;B11&#34;, &#34;B12&#34;),&#34;NDTI&#34;) try_index(quote((bands$B8- bands$B11)/(bands$B8 + bands$B11)), c(&#34;B8&#34;, &#34;B11&#34;),&#34;NDII&#34;) try_index(quote((bands$B8- bands$B12)/(bands$B8 + bands$B12)), c(&#34;B8&#34;, &#34;B12&#34;),&#34;NBRI&#34;) try_index(quote((bands$B8- bands$B4)/(bands$B8 + bands$B4)), c(&#34;B8&#34;, &#34;B4&#34;),&#34;NDVI&#34;) try_index(quote((bands$B6- bands$B4)/(bands$B6 + bands$B4)), c(&#34;B6&#34;, &#34;B4&#34;),&#34;RedEdge_NDVI1&#34;) try_index(quote((bands$B7- bands$B4)/(bands$B7 + bands$B4)), c(&#34;B7&#34;, &#34;B4&#34;),&#34;RedEdge_NDVI2&#34;) try_index(quote((bands$B7- bands$B3)/(bands$B7 + bands$B3)), c(&#34;B7&#34;, &#34;B3&#34;),&#34;GNDVI&#34;) try_index(quote((bands$B7- bands$B2)/(bands$B7 + bands$B2)), c(&#34;B7&#34;, &#34;B2&#34;),&#34;NDTSM&#34;) try_index(quote((bands$B6- bands$B5)/(bands$B6 + bands$B5)), c(&#34;B6&#34;, &#34;B5&#34;),&#34;RENDVI&#34;) try_index(quote((bands$B12- bands$B7)/(bands$B12 + bands$B7)), c(&#34;B12&#34;, &#34;B7&#34;),&#34;NDI&#34;) try_index(quote((bands$B7- bands$B6)/(bands$B6 + bands$B7)), c(&#34;B6&#34;, &#34;B7&#34;),&#34;REDI&#34;) try_index(quote((bands$B3- bands$B11)/(bands$B3 + bands$B11)), c(&#34;B3&#34;, &#34;B11&#34;),&#34;MNDW&#34;) try_index(quote((bands$B3- bands$B8)/(bands$B3 + bands$B8)), c(&#34;B3&#34;, &#34;B8&#34;),&#34;NDWI1&#34;) try_index(quote((bands$B5- bands$B12)/(bands$B5 + bands$B12)), c(&#34;B5&#34;, &#34;B12&#34;),&#34;NDWI2&#34;) try_index(quote((bands$B8A- bands$B12)/(bands$B8A + bands$B12)), c(&#34;B8A&#34;, &#34;B12&#34;),&#34;LSWI&#34;) try_index(quote((bands$B8- (bands$B5 + bands$B1))/(bands$B8 + bands$B5 + bands$B1)), c(&#34;B1&#34;,&#34;B5&#34;, &#34;B9&#34;), &#34;RBNDVI&#34;) try_index(quote((bands$B3- bands$B4)/(bands$B3 + bands$B4)), c(&#34;B3&#34;, &#34;B4&#34;),&#34;NDChla&#34;) try_index(quote((bands$B12- bands$B1)/(bands$B12 + bands$B1)), c(&#34;B1&#34;, &#34;B12&#34;),&#34;NDNIRBlue&#34;) try_index(quote((2*bands$B3- bands$B4 - bands$B2)/(2*bands$B3 + bands$B4 + bands$B2)), c(&#34;B2&#34;,&#34;B3&#34;, &#34;B4&#34;), &#34;GLI&#34;) cat(&#34;‱ Усі доступні індекси обчисленота збережено!
&#34;) # Allavailable indices have been calculated and saved! library(terra) library(vegan) # === 1. Встановлюємо директорії та отримуємо спільні індекси === # === 1.Set directories and obtain common indices === dir_2022&lt;- &#34;D:/GIS Data/SENTINEL/Indices_2022&#34; dir_2024&lt;- &#34;D:/GIS Data/SENTINEL/Indices_2024&#34; get_index_name&lt;- function(path) { gsub(&#34;_\d{4}\.tif$&#34;,&#34;&#34;, basename(path)) } files_2022&lt;- list.files(dir_2022, pattern = &#34;\.tif$&#34;, full.names = TRUE) files_2024&lt;- list.files(dir_2024, pattern = &#34;\.tif$&#34;, full.names = TRUE) indices_2022&lt;- get_index_name(files_2022) indices_2024&lt;- get_index_name(files_2024) common_indices&lt;- intersect(indices_2022, indices_2024) cat(&#34;‱ Спільні індекси:&#34;,paste(common_indices, collapse = &#34;, &#34;), &#34;
&#34;) # Printcommon indices available for both years # === 2. Завантаження шаблонного растру (наприклад,AC_Index_2022.tif) === # === 2.Loading template raster (e.g., AC_Index_2022.tif) === template_path&lt;- &#34;D:/GIS Data/SENTINEL/Indices_2022/AC_Index_2022.tif&#34; template &lt;- rast(template_path) # === 3. Функція для перетворення растрових даних у матрицю === # === 3.Function to convert raster data into a matrix === rast_to_matrix&lt;- function(file_list, index_names, template) { mat &lt;- list() for (i in seq_along(index_names)) { fname &lt;- file_list[grepl(index_names[i],file_list)] if (length(fname) == 0) next r &lt;- rast(fname[1]) if (!compareGeom(r, template, stopOnError =FALSE)) { r &lt;- resample(r, template, method =&#34;bilinear&#34;) } mat[[index_names[i]]] &lt;- values(r) } return(do.call(cbind, mat)) } mat_2022&lt;- rast_to_matrix(files_2022, common_indices, template) mat_2024&lt;- rast_to_matrix(files_2024, common_indices, template) # === 4. Видалення NA та Inf (формуємо підмножину пікселів) === # === 4.Removing NA and Inf (forming a subset of pixels) === bad_rows&lt;- apply(mat_2022, 1, function(x) any(is.na(x) | is.infinite(x))) | apply(mat_2024, 1, function(x)any(is.na(x) | is.infinite(x))) mat_2022_clean&lt;- mat_2022[!bad_rows, ] mat_2024_clean&lt;- mat_2024[!bad_rows, ] colnames(mat_2022_clean)&lt;- common_indices colnames(mat_2024_clean)&lt;- common_indices cat(&#34;🧹 Залишено пікселів:&#34;,nrow(mat_2022_clean), &#34;з&#34;, nrow(mat_2022), &#34;
&#34;) # Reportnumber of pixels kept after cleaning # Запам&#39;ятовуємо індекси використаних клітин (у порядкушаблону) # Saveindices of used cells (according to template order) sel &lt;-which(!bad_rows) # ці індекси відповідають рядкам у mat_2022_clean X_2022&lt;- mat_2022_clean X_2024&lt;- mat_2024_clean # --- 2.PCA для кожного року --- # --- 2.PCA for each year --- pca_2022&lt;- rda(X_2022, scale = TRUE) pca_2024&lt;- rda(X_2024, scale = TRUE) # --- 3. Витяг PC1 --- # --- 3.Extract PC1 (first two principal components) --- pc_2022&lt;- scores(pca_2022, display = &#34;sites&#34;, choices = c(1,2))[, 1:2] pc_2024&lt;- scores(pca_2024, display = &#34;sites&#34;, choices = c(1,2))[, 1:2] # === 7.Procrustes аналіз (вирівнюємо 2024 до 2022) === # === 7.Procrustes analysis (align 2024 to 2022) === proc &lt;-procrustes(pc_2022, pc_2024, scale = FALSE, symmetric = TRUE) # === 5. Перестановковий тест # === 5.Permutation test === proc_test&lt;- protest(pc_2022, pc_2024, permutations = 999) Yhat &lt;- proc$Yrot # вирівняні координати для 2024 (підмножина, для тих клітин, щовикористовувались) # Yhatcontains aligned coordinates for 2024 for the subset of used pixels # === 8. Обчислюємо залишки (деформації) для підмножинипікселів === # === 8.Calculate residuals (deformations) for the pixel subset === resid_PC1_subset&lt;- Yhat[, 1] - pc_2022[, 1] resid_PC2_subset&lt;- Yhat[, 2] - pc_2022[, 2] # === 9. Створюємо повні вектори залишків для всіх клітиншаблону === # === 9.Create full residual vectors for all template cells === n_cells&lt;- ncell(template) resid_PC1_full&lt;- rep(NA, n_cells) resid_PC2_full&lt;- rep(NA, n_cells) resid_PC1_full[sel]&lt;- resid_PC1_subset resid_PC2_full[sel]&lt;- resid_PC2_subset # === 10. Створення растрових шарів з залишками за шаблоном=== # === 10.Create raster layers of residuals based on the template === r_PC1 &lt;-setValues(template, resid_PC1_full) r_PC2 &lt;-setValues(template, resid_PC2_full) # Переконаємося, що CRS збережено # Ensurethat the CRS is maintained crs(r_PC1)&lt;- crs(template) crs(r_PC2)&lt;- crs(template) # === 11. Візуалізація карти прокрустових деформацій === # === 11.Visualize the Procrustes deformation map === windowsFonts(Times= windowsFont(&#34;Times New Roman&#34;)) par(family= &#34;Times&#34;, mar = c(3,3,0.5,0.5), mfrow = c(1, 2)) plot(r_PC1,main = &#34;PC1&#34;, col = hcl.colors(100, &#34;Spectral&#34;)) plot(r_PC2,main = &#34;PC2&#34;, col = hcl.colors(100, &#34;Spectral&#34;)) # === 12. (Опціонально) Збереження результатів === # === 12.(Optional) Save the results === writeRaster(r_PC1,&#34;D:/GIS Data/SENTINEL/Output/proc_deform_PC1.tif&#34;, overwrite = TRUE) writeRaster(r_PC2,&#34;D:/GIS Data/SENTINEL/Output/proc_deform_PC2.tif&#34;, overwrite = TRUE) # Завантажуємо векторні дані з точками з shapefile # Loadvector data of points from a shapefile points&lt;- vect(&#34;D:/Science/Хортиця/Plants_Total.shp&#34;) # Об&#39;єднуємо растрові шари в один стек. # Combinethe raster layers into one stack. rasters_stack&lt;- c(r_PC1, r_PC2, r_PC3, r_PC4) # Екстрагуємо значення для кожного пункту. Функція повертаєdata.frame, # де перший стовпець – ідентифікатор точки, а інші –значення відповідно до входжень у кожен шар. # Extractvalues for each point. The function returns a data.frame where the first columnis the point ID and the others are the values from each layer. extracted_values&lt;- extract(rasters_stack, points) # Переглянемо отримані дані # Displaythe extracted data print(head(extracted_values)) # Припускаємо, що extracted_values містить 5 стовпців, деперший — &#34;ID&#34; # та 4 стовпці зданими # Assumethat extracted_values contains 5 columns: the first being &#34;ID&#34; andthe next 4 the data values. names(extracted_values)&lt;- c(&#34;ID&#34;, &#34;PC1&#34;, &#34;PC2&#34;, &#34;PC3&#34;,&#34;PC4&#34;) # Перевіряємо, як виглядають перші рядки # Check thefirst few rows head(extracted_values) # Зберігаємо data.frame у файл (CSV, наприклад) # Save thedata.frame to a file (e.g., CSV